cd /workspaces/grounded-novelty-ai-6ac8-claude
source .venv/bin/activate
python3 - << 'EOF'
import json, glob
seen={}
for fn in ["/tmp/pf_q1.json","/tmp/pf_q2.json","/tmp/pf_q3.json","/tmp/pf_q4.json"]:
    try:
        d=json.load(open(fn))
    except Exception as e:
        print("skip",fn,e); continue
    for p in d.get('papers',[]):
        t=p['title'].strip().lower()
        if t not in seen or p.get('relevance',0)>seen[t].get('relevance',0):
            seen[t]=p
papers=list(seen.values())
papers.sort(key=lambda p:(-p.get('relevance',0), -(p.get('citations') or 0)))
print("TOTAL UNIQUE:", len(papers))
print("relevance==3:", sum(1 for p in papers if p.get('relevance')==3))
print("relevance>=2:", sum(1 for p in papers if (p.get('relevance') or 0)>=2))
json.dump(papers, open("/tmp/all_papers.json","w"), indent=2)
print("\n=== relevance 3 papers ===")
for p in papers:
    if p.get('relevance')==3:
        print(f"{p['year']} | cite={p['citations']} | {p['title']}")
        print("   ", p['url'])
EOF

